import pika

# Create connection to RabbitMQ server
connection = pika.BlockingConnection(pika.ConnectionParameters('localhost', 5672))
channel = connection.channel()

# Declare queue for task messages
queue = channel.queue_declare(queue='tasks', durable=True)

# Implement publisher that sends task messages to the queue
def publish_task(message):
    channel.basic_publish(exchange='', routing_key=queue, body=message, properties=pika.BasicProperties(delivery_mode=2))

# Implement consumer that processes task messages from the queue
def process_task(ch, method, properties, body):
    print("Received task message:", body)
    # Process task here
    ch.basic_ack(delivery_tag=method.delivery_tag)

# Start consuming messages from the queue
channel.basic_consume(queue=queue, on_message_callback=process_task, auto_ack=False)

# Publish a task message to the queue
publish_task("Hello, world!")

# Close connection to RabbitMQ server
connection.close()